PRAGMA foreign_keys = ON;

CREATE TABLE wallets (
  wallet_id TEXT PRIMARY KEY,
  label TEXT NOT NULL
);

CREATE TABLE wallet_totals (
  wallet_id TEXT PRIMARY KEY REFERENCES wallets(wallet_id) ON DELETE CASCADE,
  settled_cents INTEGER NOT NULL DEFAULT 0
);

CREATE TRIGGER seed_wallet_total
AFTER INSERT ON wallets
BEGIN
  INSERT INTO wallet_totals(wallet_id, settled_cents) VALUES (NEW.wallet_id, 0);
END;

CREATE TABLE settlement_batches (
  batch_id TEXT PRIMARY KEY,
  status TEXT NOT NULL CHECK (status IN ('draft', 'posted', 'void')),
  label TEXT NOT NULL
);

CREATE TABLE settlement_lines (
  line_id TEXT PRIMARY KEY,
  batch_id TEXT NOT NULL REFERENCES settlement_batches(batch_id),
  wallet_id TEXT NOT NULL REFERENCES wallets(wallet_id),
  cents INTEGER NOT NULL CHECK (cents <> 0)
);

