import sqlite3
from pathlib import Path

import pytest


ROOT = Path(__file__).resolve().parents[1]


def open_database():
    db = sqlite3.connect(":memory:")
    db.row_factory = sqlite3.Row
    for path in (
        "sql/001_schema.sql",
        "sql/010_batch_state.sql",
        "sql/020_posted_lines.sql",
    ):
        db.executescript((ROOT / path).read_text())
    return db


def totals(db):
    return {
        row["wallet_id"]: row["settled_cents"]
        for row in db.execute("SELECT wallet_id, settled_cents FROM wallet_totals")
    }


def test_fresh_post_void_and_rollback_controls():
    db = open_database()
    db.executemany(
        "INSERT INTO wallets(wallet_id, label) VALUES (?, ?)",
        [("a", "Alpha"), ("b", "Beta")],
    )
    db.execute("INSERT INTO settlement_batches VALUES ('batch-1', 'draft', 'Day one')")
    db.executemany(
        "INSERT INTO settlement_lines VALUES (?, 'batch-1', ?, ?)",
        [("line-a", "a", 125), ("line-b", "b", -125)],
    )
    assert totals(db) == {"a": 0, "b": 0}

    db.execute("UPDATE settlement_batches SET status = 'posted' WHERE batch_id = 'batch-1'")
    assert totals(db) == {"a": 125, "b": -125}
    report = db.execute((ROOT / "sql/wallet_report.sql").read_text()).fetchall()
    assert [(row["wallet_id"], row["settled_cents"]) for row in report] == [
        ("a", 125),
        ("b", -125),
    ]

    db.execute("UPDATE settlement_batches SET status = 'void' WHERE batch_id = 'batch-1'")
    assert totals(db) == {"a": 0, "b": 0}
    db.commit()

    with pytest.raises(RuntimeError):
        with db:
            db.execute("INSERT INTO settlement_batches VALUES ('batch-2', 'draft', 'Abort')")
            db.execute("INSERT INTO settlement_lines VALUES ('line-c', 'batch-2', 'a', 80)")
            db.execute(
                "UPDATE settlement_batches SET status = 'posted' WHERE batch_id = 'batch-2'"
            )
            raise RuntimeError("cancel transaction")
    assert totals(db) == {"a": 0, "b": 0}
